testbench:
`timescale 1ns/1ps
module tb;
  reg clk;
  reg reset;
  wire [3:0] q;
  integer cycle;

  count10 dut(.clk(clk), .reset(reset), .q(q));

  always #5 clk = ~clk;

  task step_check;
    input [3:0] expected;
    begin
      @(posedge clk);
      #1;
      if (q !== expected) begin
        $display("FAIL expected=%0d got=%0d", expected, q);
        $fatal(1);
      end
    end
  endtask

  initial begin
    clk = 0;
    reset = 1;
    step_check(4'd0);

    reset = 0;
    for (cycle = 1; cycle <= 9; cycle = cycle + 1) begin
      step_check(cycle[3:0]);
    end
    step_check(4'd0);
    step_check(4'd1);

    reset = 1;
    step_check(4'd0);

    $display("PASS");
    $finish;
  end
endmodule

reference_rtl:
module count10(input clk, input reset, output reg [3:0] q);
  always @(posedge clk) begin
    if (reset)
      q <= 4'd0;
    else if (q == 4'd9)
      q <= 4'd0;
    else
      q <= q + 4'd1;
  end
endmodule
